import jwt
import json
from datetime import datetime
from typing import Dict, Any, Optional, Union
import sys


def decode_jwt_token(
    token: str,
    secret_key: Optional[str] = None,
    verify_signature: bool = True,
    algorithms: Optional[list] = None,
    audience: Optional[Union[str, list]] = None,
    issuer: Optional[str] = None,
    verify_exp: bool = True,
    verify_nbf: bool = True,
    verify_iat: bool = True,
    verify_aud: bool = True,
    leeway: int = 0
) -> Dict[str, Any]:
    """
    Decode and verify JWT token for debugging purposes.
    
    Args:
        token: JWT token string
        secret_key: Secret key for verification (None for unverified decode)
        verify_signature: Whether to verify the signature
        algorithms: List of allowed algorithms (default: ['HS256', 'HS384', 'HS512', 'RS256', 'RS384', 'RS512'])
        audience: Expected audience claim
        issuer: Expected issuer claim
        verify_exp: Verify expiration time
        verify_nbf: Verify not before time
        verify_iat: Verify issued at time
        verify_aud: Verify audience claim
        leeway: Time leeway in seconds for time-based claims
        
    Returns:
        Dictionary containing decoded token information
    """
    
    if algorithms is None:
        algorithms = ['HS256', 'HS384', 'HS512', 'RS256', 'RS384', 'RS512', 'ES256', 'ES384', 'ES512']
    
    result = {
        'valid': False,
        'header': None,
        'payload': None,
        'signature_valid': False,
        'errors': [],
        'warnings': []
    }
    
    try:
        # First, decode without verification to inspect contents
        unverified_header = jwt.get_unverified_header(token)
        result['header'] = unverified_header
        
        unverified_payload = jwt.decode(
            token,
            options={
                'verify_signature': False,
                'verify_exp': False,
                'verify_nbf': False,
                'verify_iat': False,
                'verify_aud': False
            }
        )
        result['payload'] = unverified_payload
        
        # Check algorithm
        token_algorithm = unverified_header.get('alg', 'none')
        if token_algorithm.lower() == 'none':
            result['errors'].append('CRITICAL: Token uses "none" algorithm - this is insecure!')
            result['warnings'].append('Token signature cannot be verified with "none" algorithm')
        elif token_algorithm not in algorithms:
            result['warnings'].append(f'Token algorithm "{token_algorithm}" not in allowed algorithms: {algorithms}')
        
        # Verify signature if requested and secret key provided
        if verify_signature and secret_key and token_algorithm.lower() != 'none':
            try:
                options = {
                    'verify_signature': True,
                    'verify_exp': verify_exp,
                    'verify_nbf': verify_nbf,
                    'verify_iat': verify_iat,
                    'verify_aud': verify_aud,
                    'require_exp': False,
                    'require_nbf': False,
                    'require_iat': False
                }
                
                decode_kwargs = {
                    'jwt': token,
                    'key': secret_key,
                    'algorithms': algorithms,
                    'options': options,
                    'leeway': leeway
                }
                
                if audience:
                    decode_kwargs['audience'] = audience
                if issuer:
                    decode_kwargs['issuer'] = issuer
                
                verified_payload = jwt.decode(**decode_kwargs)
                result['signature_valid'] = True
                result['valid'] = True
                result['payload'] = verified_payload
                
            except jwt.ExpiredSignatureError:
                result['errors'].append('Token has expired')
                result['signature_valid'] = True  # Signature is valid, but token expired
            except jwt.InvalidSignatureError:
                result['errors'].append('Invalid signature')
            except jwt.InvalidAudienceError:
                result['errors'].append('Invalid audience')
            except jwt.InvalidIssuerError:
                result['errors'].append('Invalid issuer')
            except jwt.ImmatureSignatureError:
                result['errors'].append('Token not yet valid (nbf claim)')
            except jwt.InvalidIssuedAtError:
                result['errors'].append('Invalid issued at time (iat claim)')
            except jwt.InvalidAlgorithmError as e:
                result['errors'].append(f'Invalid algorithm: {str(e)}')
            except Exception as e:
                result['errors'].append(f'Verification error: {str(e)}')
        elif not verify_signature:
            result['warnings'].append('Signature verification skipped')
        elif not secret_key:
            result['warnings'].append('No secret key provided - signature not verified')
        
        # Analyze payload claims
        if result['payload']:
            current_time = datetime.utcnow().timestamp()
            
            # Check expiration
            if 'exp' in result['payload']:
                exp_time = result['payload']['exp']
                exp_datetime = datetime.utcfromtimestamp(exp_time)
                result['payload']['exp_readable'] = exp_datetime.isoformat() + 'Z'
                
                if exp_time < current_time:
                    result['warnings'].append(f'Token expired at {exp_datetime.isoformat()}Z')
                else:
                    time_until_exp = exp_time - current_time
                    result['warnings'].append(f'Token expires in {int(time_until_exp)} seconds')
            else:
                result['warnings'].append('No expiration claim (exp) found')
            
            # Check not before
            if 'nbf' in result['payload']:
                nbf_time = result['payload']['nbf']
                nbf_datetime = datetime.utcfromtimestamp(nbf_time)
                result['payload']['nbf_readable'] = nbf_datetime.isoformat() + 'Z'
                
                if nbf_time > current_time:
                    result['warnings'].append(f'Token not valid until {nbf_datetime.isoformat()}Z')
            
            # Check issued at
            if 'iat' in result['payload']:
                iat_time = result['payload']['iat']
                iat_datetime = datetime.utcfromtimestamp(iat_time)
                result['payload']['iat_readable'] = iat_datetime.isoformat() + 'Z'
            
            # Check for common claims
            if 'sub' not in result['payload']:
                result['warnings'].append('No subject claim (sub) found')
            if 'aud' not in result['payload']:
                result['warnings'].append('No audience claim (aud) found')
            if 'iss' not in result['payload']:
                result['warnings'].append('No issuer claim (iss) found')
        
    except jwt.DecodeError as e:
        result['errors'].append(f'Failed to decode token: {str(e)}')
    except Exception as e:
        result['errors'].append(f'Unexpected error: {str(e)}')
    
    return result


def print_token_info(token: str, secret_key: Optional[str] = None, verify: bool = True):
    """
    Print formatted JWT token information for debugging.
    
    Args:
        token: JWT token string
        secret_key: Secret key for verification
        verify: Whether to verify the signature
    """
    result = decode_jwt_token(token, secret_key=secret_key, verify_signature=verify)
    
    print("=" * 80)
    print("JWT TOKEN ANALYSIS")
    print("=" * 80)
    
    print("\nHEADER:")
    if result['header']:
        print(json.dumps(result['header'], indent=2))
    else:
        print("  Unable to decode header")
    
    print("\nPAYLOAD:")
    if result['payload']:
        print(json.dumps(result['payload'], indent=2, default=str))
    else:
        print("  Unable to decode payload")
    
    print("\nVALIDATION:")
    print(f"  Valid: {result['valid']}")
    print(f"  Signature Valid: {result['signature_valid']}")
    
    if result['errors']:
        print("\nERRORS:")
        for error in result['errors']:
            print(f"  ❌ {error}")
    
    if result['warnings']:
        print("\nWARNINGS:")
        for warning in result['warnings']:
            print(f"  ⚠️  {warning}")
    
    print("=" * 80)


